# scripts/compute-scorecard.py
from dataclasses import dataclass

WEIGHTS = {
    "eval_health":      0.30,
    "security_posture": 0.30,
    "operational":      0.20,
    "process":          0.10,
    "cost_efficiency":  0.10,
}

def score_metric(value: float, healthy: float, amber: float, higher_is_better: bool = True) -> float:
    """Return 0–100 score. healthy threshold = 100, amber = 70, red = 0."""
    if higher_is_better:
        if value >= healthy:
            return 100.0
        if value >= amber:
            return 70.0 + 30.0 * (value - amber) / (healthy - amber)
        return max(0.0, 70.0 * value / amber)
    else:
        # lower is better (latency, error rate, etc.)
        if value <= healthy:
            return 100.0
        if value <= amber:
            return 70.0 + 30.0 * (amber - value) / (amber - healthy)
        return max(0.0, 70.0 * (1.0 - (value - amber) / amber))


def compute_scorecard(metrics: dict) -> dict:
    """
    metrics: dict mapping dimension -> list of (score_0_to_100) values
    Returns overall score, dimension scores, and status.
    """
    dimension_scores = {
        dim: sum(scores) / len(scores)
        for dim, scores in metrics.items()
    }

    weighted = sum(
        dimension_scores[dim] * WEIGHTS[dim]
        for dim in WEIGHTS
    )

    # Security override: any security metric amber/red → overall Red
    security_score = dimension_scores.get("security_posture", 100)
    if security_score < 95:
        status = "RED"
    elif weighted >= 85:
        status = "GREEN"
    elif weighted >= 70:
        status = "AMBER"
    else:
        status = "RED"

    return {
        "overall_score": round(weighted, 1),
        "status": status,
        "dimension_scores": {k: round(v, 1) for k, v in dimension_scores.items()},
    }

# scripts/collect-scorecard-data.py
import json, os, subprocess, pathlib
from datetime import datetime, timedelta

# --- Eval Health ---
def collect_eval_health():
    """Read CI eval gate results from the last sprint's GitHub Actions runs."""
    # Example: parse the most recent Gate 3 run result
    # In practice, fetch from GitHub Actions API or a stored artifacts
    eval_results_path = pathlib.Path("ci-artifacts/eval-results.json")
    if not eval_results_path.exists():
        return {}
    with open(eval_results_path) as f:
        data = json.load(f)
    return {
        "pass_rate": data.get("pass_rate", 0.0),
        "baseline_pass_rate": data.get("baseline_pass_rate", 0.0),
        "total_cases": data.get("total_cases", 0),
        "flaky_rate": data.get("flaky_rate", 0.0),
    }

# --- Security Posture ---
def collect_security_posture():
    """Check injection probe results and GitHub security issues."""
    injection_path = pathlib.Path("ci-artifacts/injection-results.json")
    injection_pass_rate = 1.0
    if injection_path.exists():
        with open(injection_path) as f:
            data = json.load(f)
        total = data.get("total_probes", 0)
        passed = data.get("passed_probes", 0)
        injection_pass_rate = passed / total if total > 0 else 1.0

    # Open security issues: query GitHub CLI
    try:
        result = subprocess.run(
            ["gh", "issue", "list", "--label", "security", "--state", "open", "--json", "number"],
            capture_output=True, text=True, timeout=30
        )
        issues = json.loads(result.stdout)
        open_security_issues = len(issues)
    except Exception:
        open_security_issues = 0

    return {
        "injection_pass_rate": injection_pass_rate,
        "open_security_issues": open_security_issues,
    }

# --- Operational ---
def collect_operational():
    """Read from monitoring dashboard export or APM API."""
    ops_path = pathlib.Path("ci-artifacts/operational-metrics.json")
    if not ops_path.exists():
        return {}
    with open(ops_path) as f:
        return json.load(f)

def main():
    scorecard_data = {
        "sprint": datetime.utcnow().strftime("W%V"),
        "collected_at": datetime.utcnow().isoformat(),
        "eval_health": collect_eval_health(),
        "security_posture": collect_security_posture(),
        "operational": collect_operational(),
    }
    with open("scorecard-data.json", "w") as f:
        json.dump(scorecard_data, f, indent=2)
    print(f"Scorecard data collected: {json.dumps(scorecard_data, indent=2)}")

if __name__ == "__main__":
    main()
